// ====================================================================
// ==================== ИНТЕРФЕЙС РЕДАКТОРА ====================
// ====================================================================

function renderTilesetTabs() { const c = document.getElementById('tileset-tabs-container'); c.innerHTML = ''; const letters = 'ABCDE'; projectTilesets.forEach((ts, i) => { const tab = document.createElement('div'); tab.className = 'tileset-tab' + (ts.id === activeTilesetId ? ' active' : ''); tab.innerText = letters[i] || ts.name; tab.onclick = () => { activeTilesetId = ts.id; isEraserActive = false; document.getElementById('eraser-btn').classList.remove('active'); selectedArea = {x:0,y:0,w:1,h:1}; setMode('tile'); renderTilesetTabs(); renderPalette(); }; c.appendChild(tab); }); }

function renderPalette() { const ts = projectTilesets.find(t => t.id === activeTilesetId); if (!ts || !ts.image) { paletteCanvas.width = 48; paletteCanvas.height = 48; paletteCtx.fillStyle = '#333'; paletteCtx.fillRect(0,0,48,48); return; } const containerWidth = document.getElementById('palette-canvas-container').clientWidth; paletteCols = Math.max(1, Math.floor(containerWidth / TILE_SIZE)); const imgW = ts.image.width / TILE_SIZE; const imgH = ts.image.height / TILE_SIZE; const numChunks = Math.ceil(imgW / paletteCols); const newW = paletteCols * TILE_SIZE; const newH = numChunks * imgH * TILE_SIZE; paletteCanvas.width = newW; paletteCanvas.height = newH; paletteCtx.clearRect(0, 0, newW, newH); for (let origY = 0; origY < imgH; origY++) { for (let origX = 0; origX < imgW; origX++) { const chunkIndex = Math.floor(origX / paletteCols); const localX = origX % paletteCols; const srcX = origX * TILE_SIZE; const srcY = origY * TILE_SIZE; const destX = localX * TILE_SIZE; const destY = (chunkIndex * imgH + origY) * TILE_SIZE; paletteCtx.drawImage(ts.image, srcX, srcY, TILE_SIZE, TILE_SIZE, destX, destY, TILE_SIZE, TILE_SIZE); } } updatePaletteSelection(); }

function updatePaletteSelection() { 
    const sel = document.getElementById('palette-selection'); 
    if (isEraserActive) { sel.style.display = 'none'; return; } 
    sel.style.display = 'block'; 
    sel.style.left = selectedArea.x * TILE_SIZE + 'px'; 
    sel.style.top = selectedArea.y * TILE_SIZE + 'px'; 
    sel.style.width = selectedArea.w * TILE_SIZE + 'px'; 
    sel.style.height = selectedArea.h * TILE_SIZE + 'px'; 
    // Фиолетовая подсветка выделения
    sel.style.backgroundColor = 'rgba(128, 0, 255, 0.3)'; 
    sel.style.border = '2px solid #9b59b6'; 
    sel.style.pointerEvents = 'none'; // Чтобы не мешал кликам
}

function startPaletteDrag(e) { const rect = paletteCanvas.getBoundingClientRect(); const clientX = e.clientX || (e.touches && e.touches[0].clientX); const clientY = e.clientY || (e.touches && e.touches[0].clientY); const x = Math.floor((clientX - rect.left) * (paletteCanvas.width / rect.width) / TILE_SIZE); const y = Math.floor((clientY - rect.top) * (paletteCanvas.height / rect.height) / TILE_SIZE); if (x >= 0 && y >= 0) { isDraggingPalette = true; paletteDragStart = { x, y }; selectedArea = { x, y, w: 1, h: 1 }; isEraserActive = false; document.getElementById('eraser-btn').classList.remove('active'); setMode('tile'); updatePaletteSelection(); } }

function movePaletteDrag(e) { if (!isDraggingPalette) return; e.preventDefault(); const rect = paletteCanvas.getBoundingClientRect(); const clientX = e.clientX || (e.touches && e.touches[0].clientX); const clientY = e.clientY || (e.touches && e.touches[0].clientY); let x = Math.floor((clientX - rect.left) * (paletteCanvas.width / rect.width) / TILE_SIZE); let y = Math.floor((clientY - rect.top) * (paletteCanvas.height / rect.height) / TILE_SIZE); x = Math.max(0, Math.min(x, paletteCols - 1)); y = Math.max(0, Math.min(y, (paletteCanvas.height / TILE_SIZE) - 1)); selectedArea.x = Math.min(paletteDragStart.x, x); selectedArea.y = Math.min(paletteDragStart.y, y); selectedArea.w = Math.abs(x - paletteDragStart.x) + 1; selectedArea.h = Math.abs(y - paletteDragStart.y) + 1; updatePaletteSelection(); }

function endPaletteDrag() { isDraggingPalette = false; }

paletteCanvas.addEventListener('mousedown', (e) => startPaletteDrag(e)); paletteCanvas.addEventListener('mousemove', (e) => movePaletteDrag(e)); paletteCanvas.addEventListener('mouseup', () => endPaletteDrag()); paletteCanvas.addEventListener('mouseleave', () => endPaletteDrag());
paletteCanvas.addEventListener('touchstart', (e) => { e.preventDefault(); startPaletteDrag(e); }, {passive: false}); paletteCanvas.addEventListener('touchmove', (e) => { movePaletteDrag(e); }, {passive: false}); paletteCanvas.addEventListener('touchend', () => endPaletteDrag());

function toggleEraser() { isEraserActive = !isEraserActive; document.getElementById('eraser-btn').classList.toggle('active', isEraserActive); updatePaletteSelection(); }

function renderEditorMap() { 
    if(maps.length === 0) return; 
    const m=getCurrentMap(); 
    editorCanvas.width=m.width*TILE_SIZE; 
    editorCanvas.height=m.height*TILE_SIZE; 
    editorCtx.clearRect(0,0,editorCanvas.width,editorCanvas.height); 
    drawMapOnCanvas(editorCtx, m, false, false); 
    drawMapOnCanvas(editorCtx, m, false, true); 
    editorCtx.strokeStyle='rgba(255,255,255,0.1)'; 
    for(let x=0;x<=m.width;x++){editorCtx.beginPath();editorCtx.moveTo(x*TILE_SIZE,0);editorCtx.lineTo(x*TILE_SIZE,m.height*TILE_SIZE);editorCtx.stroke();} 
    for(let y=0;y<=m.height;y++){editorCtx.beginPath();editorCtx.moveTo(0,y*TILE_SIZE);editorCtx.lineTo(m.width*TILE_SIZE,y*TILE_SIZE);editorCtx.stroke();} 
    for (let k in m.eventsData) { try { const ev = m.eventsData[k]; ensureEventPages(ev); if(!ev.pages || ev.pages.length === 0) continue; const p = ev.pages[0]; const [x, y] = k.split(',').map(Number); const char = projectCharacters.find(c => c.id === p.graphicCharId); const drawn = drawCharacter(editorCtx, char, p.graphicCharIndex || 0, x*TILE_SIZE, y*TILE_SIZE, 0, 1); if (!drawn) { editorCtx.fillStyle='rgba(255,0,0,0.7)'; editorCtx.beginPath(); const cx=x*TILE_SIZE+24,cy=y*TILE_SIZE+24; editorCtx.moveTo(cx,cy-12); editorCtx.lineTo(cx+12,cy); editorCtx.lineTo(cx,cy+12); editorCtx.lineTo(cx-12,cy); editorCtx.closePath(); editorCtx.fill(); } if(ev.name) { editorCtx.fillStyle = 'yellow'; editorCtx.font = 'bold 10px Arial'; editorCtx.fillText(ev.name, x*TILE_SIZE+2, y*TILE_SIZE+10); } } catch(e) {} } 
    if(m.playerStartPos){const px=m.playerStartPos.x*TILE_SIZE,py=m.playerStartPos.y*TILE_SIZE;editorCtx.fillStyle='rgba(0,150,255,0.6)';editorCtx.fillRect(px,py,TILE_SIZE,TILE_SIZE);editorCtx.fillStyle='#fff';editorCtx.font='bold 24px Arial';editorCtx.textAlign='center';editorCtx.textBaseline='middle';editorCtx.fillText('P',px+24,py+24);} 
    applyEditorZoom(); 
}

function getGridCoordsFromEvent(e) { const m=getCurrentMap(); const rect = editorCanvas.getBoundingClientRect(); let cx, cy; if(e.touches && e.touches.length > 0) { cx = e.touches[0].clientX; cy = e.touches[0].clientY; } else if(e.changedTouches && e.changedTouches.length > 0) { cx = e.changedTouches[0].clientX; cy = e.changedTouches[0].clientY; } else { cx = e.clientX; cy = e.clientY; } const x = Math.floor((cx - rect.left) * (editorCanvas.width / rect.width) / TILE_SIZE); const y = Math.floor((cy - rect.top) * (editorCanvas.height / rect.height) / TILE_SIZE); return {x, y, valid: x>=0 && x<m.width && y>=0 && y<m.height}; }

function floodFill(startX, startY) {
    const m = getCurrentMap(); const layerIdx = activeTilesetId - 1; const targetStr = m.mapData[startY][startX][layerIdx]; let replaceStr = ""; if (isEraserActive) { replaceStr = "0"; } else { const ts = projectTilesets.find(t => t.id === activeTilesetId); if (!ts || !ts.image) return; const imgW = ts.image.width / TILE_SIZE; const imgH = ts.image.height / TILE_SIZE; const destX = selectedArea.x; const destY = selectedArea.y; const localX = destX; const chunkIndex = Math.floor(destY / imgH); const origY = destY % imgH; const origX = chunkIndex * paletteCols + localX; const tileIndex0Based = origY * imgW + origX; replaceStr = "T" + activeTilesetId + "_" + (tileIndex0Based + 1); } if (targetStr === replaceStr) return; const queue = [[startX, startY]]; const visited = new Set(); visited.add(`${startX},${startY}`); while (queue.length > 0) { const [x, y] = queue.shift(); m.mapData[y][x][layerIdx] = replaceStr; const neighbors = [[x+1, y], [x-1, y], [x, y+1], [x, y-1]]; for (const [nx, ny] of neighbors) { if (nx >= 0 && nx < m.width && ny >= 0 && ny < m.height) { const key = `${nx},${ny}`; if (!visited.has(key) && m.mapData[ny][nx][layerIdx] === targetStr) { visited.add(key); queue.push([nx, ny]); } } } } renderEditorMap();
}

function handleMapInteraction(e) { const m=getCurrentMap(); const {x, y, valid} = getGridCoordsFromEvent(e); if(!valid) return; if(currentMode==='tile'){ const tsId = activeTilesetId; const layerIdx = tsId - 1; let changed = false; if (isEraserActive) { if(m.mapData[y][x][layerIdx] !== "0") { m.mapData[y][x][layerIdx] = "0"; changed = true; } } else { const ts = projectTilesets.find(t => t.id === tsId); if (!ts || !ts.image) return; const imgW = ts.image.width / TILE_SIZE; const imgH = ts.image.height / TILE_SIZE; for (let dy = 0; dy < selectedArea.h; dy++) { for (let dx = 0; dx < selectedArea.w; dx++) { const targetX = x + dx; const targetY = y + dy; if (targetX >= m.width || targetY >= m.height) continue; const destX = selectedArea.x + dx; const destY = selectedArea.y + dy; const localX = destX; const chunkIndex = Math.floor(destY / imgH); const origY = destY % imgH; const origX = chunkIndex * paletteCols + localX; const tileIndex0Based = origY * imgW + origX; const tileStr = "T" + tsId + "_" + (tileIndex0Based + 1); if(m.mapData[targetY][targetX][layerIdx] !== tileStr) { m.mapData[targetY][targetX][layerIdx] = tileStr; changed = true; } }} } if (changed) renderEditorMap(); } else if(currentMode==='fill'){ floodFill(x, y); } else if(currentMode==='player'){ m.playerStartPos={x,y}; renderEditorMap(); } }

function handlePointerDown(e) { if (currentMode === 'tile' || currentMode === 'fill') { isDrawing = true; handleMapInteraction(e); } else if (currentMode === 'event') { const {x, y, valid} = getGridCoordsFromEvent(e); if (!valid) return; const key = `${x},${y}`; if (Date.now() - lastClickTime < 300 && lastClickKey === key) { openEventModal(x, y); lastClickTime = 0; return; } lastClickTime = Date.now(); lastClickKey = key; const m = getCurrentMap(); if (m.eventsData[key]) { isDraggingEvent = true; draggedEventKey = key; } } else if (currentMode === 'player') { handleMapInteraction(e); } }
function handlePointerMove(e) { if (currentMode === 'tile' && isDrawing) { handleMapInteraction(e); } else if (currentMode === 'event' && isDraggingEvent && draggedEventKey) { const {x, y, valid} = getGridCoordsFromEvent(e); if (!valid) return; const newKey = `${x},${y}`; const m = getCurrentMap(); if (draggedEventKey !== newKey && !m.eventsData[newKey]) { m.eventsData[newKey] = m.eventsData[draggedEventKey]; delete m.eventsData[draggedEventKey]; draggedEventKey = newKey; renderEditorMap(); } } }
function handlePointerUp(e) { isDrawing = false; isDraggingEvent = false; draggedEventKey = null; }

// --- Обработка мыши и тачей для Canvas ---
let isPinching = false;
let lastPinchDist = 0;
let isPanning = false;
let panStartX = 0, panStartY = 0;
let panStartScrollLeft = 0, panStartScrollTop = 0;

function getTouchDistance(touch1, touch2) { const dx = touch1.clientX - touch2.clientX; const dy = touch1.clientY - touch2.clientY; return Math.sqrt(dx * dx + dy * dy); }

editorCanvas.addEventListener('mousedown', (e) => { if (currentMode === 'move') { isPanning = true; panStartX = e.clientX; panStartY = e.clientY; const container = document.getElementById('map-container'); panStartScrollLeft = container.scrollLeft; panStartScrollTop = container.scrollTop; editorCanvas.style.cursor = 'grabbing'; } else { handlePointerDown(e); } });
editorCanvas.addEventListener('mousemove', (e) => { if (isPanning) { const dx = e.clientX - panStartX; const dy = e.clientY - panStartY; const container = document.getElementById('map-container'); container.scrollLeft = panStartScrollLeft - dx; container.scrollTop = panStartScrollTop - dy; } else { handlePointerMove(e); } });
editorCanvas.addEventListener('mouseup', () => { if (isPanning) { isPanning = false; if (currentMode === 'move') editorCanvas.style.cursor = 'grab'; } handlePointerUp(); });
editorCanvas.addEventListener('mouseleave', () => { if (isPanning) { isPanning = false; if (currentMode === 'move') editorCanvas.style.cursor = 'grab'; } handlePointerUp(); });

editorCanvas.addEventListener('touchstart', (e) => { if (e.touches.length === 2) { e.preventDefault(); isPinching = true; isPanning = false; isDrawing = false; isDraggingEvent = false; lastPinchDist = getTouchDistance(e.touches[0], e.touches[1]); } else if (e.touches.length === 1) { if (currentMode === 'move') { e.preventDefault(); isPanning = true; panStartX = e.touches[0].clientX; panStartY = e.touches[0].clientY; const container = document.getElementById('map-container'); panStartScrollLeft = container.scrollLeft; panStartScrollTop = container.scrollTop; } else { e.preventDefault(); handlePointerDown(e); } } }, {passive: false});
editorCanvas.addEventListener('touchmove', (e) => { if (e.touches.length === 2 && isPinching) { e.preventDefault(); const currentDist = getTouchDistance(e.touches[0], e.touches[1]); const diff = currentDist - lastPinchDist;                 if (Math.abs(diff) > 15) {
                    // Вычисляем центр жеста щипка
                    const rect = document.getElementById('map-container').getBoundingClientRect();
                    const midX = (e.touches[0].clientX + e.touches[1].clientX) / 2 - rect.left;
                    const midY = (e.touches[0].clientY + e.touches[1].clientY) / 2 - rect.top;
                    
                    const dir = diff > 0 ? 1 : -1;
                    zoomEditor(dir, midX, midY);
                    lastPinchDist = currentDist; 
                } } else if (isPanning && e.touches.length === 1) { e.preventDefault(); const dx = e.touches[0].clientX - panStartX; const dy = e.touches[0].clientY - panStartY; const container = document.getElementById('map-container'); container.scrollLeft = panStartScrollLeft - dx; container.scrollTop = panStartScrollTop - dy; } else if (e.touches.length === 1 && currentMode !== 'move') { e.preventDefault(); handlePointerMove(e); } }, {passive: false});
editorCanvas.addEventListener('touchend', (e) => { if (e.touches.length < 2) isPinching = false; if (e.touches.length === 0) isPanning = false; if (currentMode !== 'move') handlePointerUp(e); });

// --- Сайдбар, Карты, Зум, Режимы ---
let lastMapTapTime = 0; let lastMapTapIndex = -1;
function renderMapList() { const c=document.getElementById('map-list-container'); c.innerHTML=''; maps.forEach((m,i)=>{ const it=document.createElement('div'); it.className='map-item'+(i===currentMapIndex?' active':''); it.innerText=`🗺️ ${m.name}`; it.onclick=()=>{ const now = Date.now(); if (i === lastMapTapIndex && now - lastMapTapTime < 400) { openMapSettingsModal(i); lastMapTapTime = 0; lastMapTapIndex = -1; } else { switchMap(i); lastMapTapTime = now; lastMapTapIndex = i; } }; c.appendChild(it); }); }
function toggleMapList() { const mapSection = document.getElementById('map-section'); const icon = document.getElementById('map-toggle-icon'); mapSection.classList.toggle('collapsed'); if (mapSection.classList.contains('collapsed')) { icon.innerText = '►'; } else { icon.innerText = '▼'; } setTimeout(() => renderPalette(), 50); }

function toggleSidebar() { const sidebar = document.getElementById('sidebar'); const btn = document.getElementById('sidebar-toggle-btn'); sidebar.classList.toggle('open'); if (sidebar.classList.contains('open')) { btn.innerHTML = '◄'; } else { btn.innerHTML = '►'; } }

function closeSidebarIfOpen() {
    const sidebar = document.getElementById('sidebar');
    if (sidebar.classList.contains('open')) {
        sidebar.classList.remove('open');
        document.getElementById('sidebar-toggle-btn').innerHTML = '►';
    }
}

// Закрываем сайдбар при клике/тапе на рабочую область карты
document.getElementById('map-container').addEventListener('mousedown', closeSidebarIfOpen);
document.getElementById('map-container').addEventListener('touchstart', closeSidebarIfOpen);

function scrollPalette(dir) { const el = document.getElementById('palette-area'); el.scrollBy({ top: dir * (TILE_SIZE * 2), behavior: 'smooth' }); }
function scrollScript(dir) { const el = document.getElementById('script-container'); el.scrollBy({ top: dir * 60, behavior: 'smooth' }); }
function toggleFullscreen() { if (!document.fullscreenElement) { document.documentElement.requestFullscreen().catch(err => { alert(`Ошибка полного экрана: ${err.message}`); }); } else { document.exitFullscreen(); } }
function switchMap(i) { currentMapIndex=i; ensureLayerFormat(getCurrentMap()); const m = getCurrentMap(); for(let k in m.eventsData) ensureEventPages(m.eventsData[k]); loadCurrentMapToUI();renderEditorMap();renderMapList(); }
function loadCurrentMapToUI() { const m=getCurrentMap();document.getElementById('map-width').value=m.width;document.getElementById('map-height').value=m.height; }
function applyMapSize() { const m=getCurrentMap();const nw=parseInt(document.getElementById('map-width').value)||m.width;const nh=parseInt(document.getElementById('map-height').value)||m.height;const nd=createEmptyMap(nw,nh);for(let y=0;y<Math.min(nh,m.height);y++)for(let x=0;x<Math.min(nw,m.width);x++)nd[y][x]=m.mapData[y][x];m.width=nw;m.height=nh;m.mapData=nd;if(m.playerStartPos&&(m.playerStartPos.x>=nw||m.playerStartPos.y>=nh))m.playerStartPos=null;renderEditorMap(); }
function setMode(mode) { currentMode = mode;['move','tile','fill','event','player'].forEach(m=>document.getElementById('mode-'+m).classList.toggle('active',mode===m)); if(mode === 'move') editorCanvas.style.cursor = 'grab'; else if(mode === 'fill') editorCanvas.style.cursor = 'cell'; else if(mode === 'event') editorCanvas.style.cursor = 'pointer'; else editorCanvas.style.cursor = 'crosshair'; }
function zoomEditor(dir, pivotX, pivotY) { 
    const container = document.getElementById('map-container');
    const oldZoom = editorZoom;
    
    editorZoomIndex += dir; 
    if (editorZoomIndex < 0) editorZoomIndex = 0; 
    if (editorZoomIndex >= editorZoomLevels.length) editorZoomIndex = editorZoomLevels.length - 1; 
    
    editorZoom = editorZoomLevels[editorZoomIndex];
    
    // Если точка привязки не передана (например, нажали кнопки +-/🔍), зумим в центр экрана
    if (pivotX === undefined || pivotY === undefined) {
        pivotX = container.clientWidth / 2;
        pivotY = container.clientHeight / 2;
    }

    // Магия математики: сохраняем точку под курсором/пальцем на месте
    const oldScrollLeft = container.scrollLeft;
    const oldScrollTop = container.scrollTop;

    applyEditorZoom(); // Меняем размер канваса

    // Пересчитываем скролл с учетом нового зума
    container.scrollLeft = (oldScrollLeft + pivotX) * (editorZoom / oldZoom) - pivotX;
    container.scrollTop = (oldScrollTop + pivotY) * (editorZoom / oldZoom) - pivotY;
}

function applyEditorZoom() { 
    const m = getCurrentMap(); 
    if (m) { 
        editorCanvas.style.width = (m.width * TILE_SIZE * editorZoom) + 'px'; 
        editorCanvas.style.height = (m.height * TILE_SIZE * editorZoom) + 'px'; 
        editorCanvas.style.imageRendering = 'pixelated'; 
    } 
    document.getElementById('zoom-label').innerText = Math.round(editorZoom * 100) + '%'; 
}

// Зум колёсиком мыши
document.getElementById('map-container').addEventListener('wheel', (e) => {
    e.preventDefault();
    const rect = document.getElementById('map-container').getBoundingClientRect();
    const mouseX = e.clientX - rect.left;
    const mouseY = e.clientY - rect.top;
    const dir = e.deltaY < 0 ? 1 : -1; // Вверх = приближение, вниз = отдаление
    zoomEditor(dir, mouseX, mouseY);
}, { passive: false });

// ====================================================================
// ==================== МОДАЛКА СОБЫТИЙ ====================
// ====================================================================

function openEventModal(x,y){ 
    const m=getCurrentMap(); const k=`${x},${y}`; currentEditEventKey=k; 
    if(!m.eventsData[k]){ m.eventsData[k]={name:"", pages: [{ conditionSwitchId: -1, conditionLocalSwitch: "None", graphicCharId: -1, graphicCharIndex: 0, movement: "fixed", passable: false, priority: 0, trigger: "action", commands:[] }]}; renderEditorMap(); } 
    const ev = m.eventsData[k]; ensureEventPages(ev); 
    const nameInput = document.getElementById('event-name-input'); nameInput.value = ev.name || ""; nameInput.placeholder = `Событие: ${x}, ${y}`; 
    currentEventPageIndex = 0; renderEventPageTabs(); loadCurrentPageToUI(); renderScriptLines(); 
    document.getElementById('event-modal').classList.add('active'); document.getElementById('overlay').classList.add('active'); 
}
function closeEventModal(){ 
    const m=getCurrentMap(); const ev=m.eventsData[currentEditEventKey]; 
    if(ev) { ev.name = document.getElementById('event-name-input').value; saveCurrentPageFromUI(); } 
    document.getElementById('event-modal').classList.remove('active'); document.getElementById('overlay').classList.remove('active'); currentEditEventKey=null; renderEditorMap(); 
}
function deleteCurrentEvent(){const m=getCurrentMap();if(currentEditEventKey&&confirm("Удалить событие?")){delete m.eventsData[currentEditEventKey];document.getElementById('event-modal').classList.remove('active');document.getElementById('overlay').classList.remove('active');currentEditEventKey=null;renderEditorMap();}}
function renderEventPageTabs() { const c = document.getElementById('event-page-tabs'); c.innerHTML = ''; const ev = getCurrentMap().eventsData[currentEditEventKey]; ev.pages.forEach((p, i) => { const t = document.createElement('div'); t.className = 'page-tab' + (i === currentEventPageIndex ? ' active' : ''); const nameSpan = document.createElement('span'); nameSpan.innerText = `Стр. ${i+1}`; t.appendChild(nameSpan); if (ev.pages.length > 1) { const xBtn = document.createElement('span'); xBtn.className = 'page-tab-x'; xBtn.innerText = '✖'; xBtn.onclick = (e) => { e.stopPropagation(); if (confirm(`Удалить страницу ${i+1}?`)) { ev.pages.splice(i, 1); if (currentEventPageIndex >= ev.pages.length) currentEventPageIndex = ev.pages.length - 1; loadCurrentPageToUI(); renderEventPageTabs(); renderScriptLines(); } }; t.appendChild(xBtn); } t.onclick = (e) => { if (e.target.classList.contains('page-tab-x')) return; saveCurrentPageFromUI(); currentEventPageIndex = i; loadCurrentPageToUI(); renderEventPageTabs(); renderScriptLines(); }; c.appendChild(t); }); const addBtn = document.createElement('div'); addBtn.className = 'add-page-tab'; addBtn.innerText = '+ Стр.'; addBtn.onclick = () => { ev.pages.push({ conditionSwitchId: -1, conditionLocalSwitch: "None", graphicCharId: -1, graphicCharIndex: 0, movement: "fixed", passable: false, priority: 0, trigger: "action", commands:[] }); currentEventPageIndex = ev.pages.length - 1; loadCurrentPageToUI(); renderEventPageTabs(); renderScriptLines(); }; c.appendChild(addBtn); }
function getCurrentPage() { if(!currentEditEventKey || !getCurrentMap().eventsData[currentEditEventKey]) return null; return getCurrentMap().eventsData[currentEditEventKey].pages[currentEventPageIndex]; }
function loadCurrentPageToUI() { const p = getCurrentPage(); if(!p) return; populateGraphicSelect(p.graphicCharId); document.getElementById('event-movement-select').value = p.movement || "fixed"; document.getElementById('event-passable-select').value = (p.passable === false) ? "false" : "true"; document.getElementById('event-priority-select').value = p.priority || 0; document.getElementById('event-trigger-select').value = p.trigger || "action"; populateConditionSelect(p.conditionSwitchId); document.getElementById('event-condition-lsw-select').value = p.conditionLocalSwitch || "None"; updateEventGraphic(); }
function saveCurrentPageFromUI() { const p = getCurrentPage(); if(!p) return; p.graphicCharId = parseInt(document.getElementById('event-graphic-select').value); p.conditionSwitchId = parseInt(document.getElementById('event-condition-sw-select').value); p.conditionLocalSwitch = document.getElementById('event-condition-lsw-select').value; p.movement = document.getElementById('event-movement-select').value; p.passable = document.getElementById('event-passable-select').value === 'true'; p.priority = parseInt(document.getElementById('event-priority-select').value); p.trigger = document.getElementById('event-trigger-select').value; }
function populateGraphicSelect(selectedId) { const sel = document.getElementById('event-graphic-select'); sel.innerHTML = '<option value="-1">Нет</option>'; projectCharacters.forEach(c => { const opt = document.createElement('option'); opt.value = c.id; opt.innerText = c.name; if (c.id === selectedId) opt.selected = true; sel.appendChild(opt); }); }
function updateEventGraphic() { const cId = parseInt(document.getElementById('event-graphic-select').value); const box = document.getElementById('event-graphic-preview'); box.innerHTML = ''; const p = getCurrentPage(); if(cId !== -1) { if (p.passable === true) { p.passable = false; document.getElementById('event-passable-select').value = "false"; } const char = projectCharacters.find(c => c.id === cId); if(char && char.image && char.image.width > 0) { const charsPerRow = Math.floor(char.image.width / (TILE_SIZE * 3)) || 1; const charsPerCol = Math.floor(char.image.height / (TILE_SIZE * 4)) || 1; const totalChars = charsPerRow * charsPerCol; const container = document.createElement('div'); container.style.display = 'flex'; container.style.flexWrap = 'wrap'; container.style.gap = '4px'; container.style.maxWidth = '220px'; for(let i = 0; i < totalChars; i++) { const charDiv = document.createElement('div'); charDiv.style.width = '64px'; charDiv.style.height = '64px'; charDiv.style.borderRadius = '4px'; charDiv.style.cursor = 'pointer'; charDiv.style.border = i === (p.graphicCharIndex||0) ? '3px solid #4CAF50' : '3px solid #555'; charDiv.style.backgroundColor = '#111'; charDiv.style.backgroundImage = `url(${char.imageSrc})`; charDiv.style.imageRendering = 'pixelated'; const bgW = charsPerRow * 3 * 64; const bgH = charsPerCol * 4 * 64; charDiv.style.backgroundSize = `${bgW}px ${bgH}px`; const bgX = (i % charsPerRow) * 3 * 64 + 1 * 64; const bgY = Math.floor(i / charsPerRow) * 4 * 64; charDiv.style.backgroundPosition = `-${bgX}px -${bgY}px`; charDiv.onclick = () => { p.graphicCharIndex = i; updateEventGraphic(); }; container.appendChild(charDiv); } box.appendChild(container); } } else { box.innerHTML = '<span style="color:#555;font-size:10px;">Нет графики</span>'; p.graphicCharIndex = 0; } }
function cycleEventGraphic() { const p = getCurrentPage(); if (!p) return; const currentId = p.graphicCharId; const chars = projectCharacters; let nextId = -1; if (currentId === -1) { if (chars.length > 0) nextId = chars[0].id; } else { const currentIndex = chars.findIndex(c => c.id === currentId); if (currentIndex !== -1 && currentIndex < chars.length - 1) { nextId = chars[currentIndex + 1].id; } else { nextId = -1; } } p.graphicCharId = nextId; document.getElementById('event-graphic-select').value = nextId; updateEventGraphic(); }

