function handleNewSwitchSelect(selectEl) { if (selectEl.value === "-2") { const name = prompt("Имя нового переключателя:"); if (name && name.trim() !== "") { const newId = gameSwitches.length > 0 ? Math.max(...gameSwitches.map(s=>s.id)) + 1 : 1; gameSwitches.push({id: newId, name: name.trim(), state: false}); populateCmdSelects(); populateConditionSelect(newId); } else { selectEl.value = "-1"; } } }
function populateConditionSelect(selectedId) { const sel = document.getElementById('event-condition-sw-select'); sel.innerHTML = '<option value="-1">Нет</option>'; gameSwitches.forEach(sw => { const opt = document.createElement('option'); opt.value = sw.id; opt.innerText = `[S${sw.id}] ${sw.name}`; if (sw.id === selectedId) opt.selected = true; sel.appendChild(opt); }); const newOpt = document.createElement('option'); newOpt.value = "-2"; newOpt.innerText = "[ + Новый ]"; sel.appendChild(newOpt); }
function renderScriptLines(){ const c=document.getElementById('script-container'); c.innerHTML=''; if(!currentEditEventKey) return; const p = getCurrentPage(); if(!p) return; const cmds=p.commands; const lc=Math.max(10,cmds.length+2); let depth=0; for(let i=0;i<lc;i++){ const l=document.createElement('div'); l.className='script-line'; const cmd=cmds[i]; let currentDepth = depth; if(cmd && (cmd.type==='else' || cmd.type==='choice_branch' || cmd.type==='choice_end')) currentDepth = depth - 1; if(cmd && cmd.type==='if_end') currentDepth = depth - 1; l.style.paddingLeft=(10+currentDepth*20)+'px'; if(cmd){ const s=document.createElement('span'); if(cmd.type==='message'){s.className='cmd-message';s.innerText=`💬 "${cmd.text}"`;} else if(cmd.type==='switch'){s.className='cmd-switch';s.innerText=`🔧 Глоб. [S${cmd.switchId}] ${cmd.value?'ВКЛ':'ВЫКЛ'}`;} else if(cmd.type==='local_switch'){s.className='cmd-switch';s.innerText=`⚙️ Лок. [${cmd.switch}] ${cmd.value?'ВКЛ':'ВЫКЛ'}`;} else if(cmd.type==='variable'){s.className='cmd-variable';const v=gameVariables.find(x=>x.id===cmd.variableId);const op=cmd.operation==='set'?'=':cmd.operation==='add'?'+':'-';s.innerText=`🔢 [V${cmd.variableId}] ${v?v.name:'?'} ${op} ${cmd.operand}`;} else if(cmd.type==='teleport'){s.className='cmd-teleport';const tMap=maps.find(m=>m.mapId===cmd.mapId);s.innerText=`🚀 Телепорт: ${tMap?tMap.name:'?'} (X:${cmd.x}, Y:${cmd.y})`;} else if(cmd.type==='if_start'){s.className='cmd-if';let condTxt='';if(cmd.conditionType==='switch'){condTxt=`Глоб. [S${cmd.switchId}] ${cmd.conditionValue?'ВКЛ':'ВЫКЛ'}`} else if(cmd.conditionType==='local_switch'){condTxt=`Лок. [${cmd.switch}] ${cmd.conditionValue?'ВКЛ':'ВЫКЛ'}`} else {const v=gameVariables.find(x=>x.id===cmd.variableId);condTxt=`[V${cmd.variableId}] ${v?v.name:''} ${cmd.conditionOp} ${cmd.conditionVal}`;}s.innerText=`❓ Если ${condTxt}:`;depth++;} else if(cmd.type==='else'){s.className='cmd-else';s.innerText=`↪️ Иначе:`;} else if(cmd.type==='if_end'){s.className='cmd-if-end';s.innerText=`🛑 Конец Если`;depth--;} else if(cmd.type==='choice'){s.className='cmd-choice';s.innerText=`🔀 Выбор: ${cmd.choices.filter(c=>c).join(', ')}`; depth++;} else if(cmd.type==='choice_branch'){s.className='cmd-choice-branch';s.innerText=`↪️ Вариант ${cmd.branchIndex+1}: "${cmd.text}"`;} else if(cmd.type==='choice_end'){s.className='cmd-choice-end';s.innerText=`🛑 Конец Выбора`;depth--;} l.appendChild(s); if(cmd.type !== 'else' && cmd.type !== 'if_end' && cmd.type !== 'choice_branch' && cmd.type !== 'choice_end') l.onclick = () => editCommand(i, cmd); } else { l.classList.add('empty-line'); l.innerText='@ Пусто (нажмите)'; l.onclick=()=>{activeLineIndex=i; openAddCmdModal();}; } c.appendChild(l); } }
function openAddCmdModal(){isEditingCommand = false; editCommandIndex = -1;document.getElementById('cmd-modal-title').innerText = "Добавить команду";document.getElementById('delete-cmd-btn').style.display = 'none';document.getElementById('cmd-choices').style.display='grid';document.getElementById('message-textarea').value = ''; ['message-input-area','switch-input-area','local-switch-input-area','var-input-area','if-input-area','choice-input-area','teleport-input-area'].forEach(id=>document.getElementById(id).classList.remove('active'));document.getElementById('add-cmd-modal').classList.add('active');populateCmdSelects();}
function editCommand(index, cmd) {isEditingCommand = true; editCommandIndex = index;document.getElementById('cmd-modal-title').innerText = "Редактировать команду";document.getElementById('delete-cmd-btn').style.display = 'block';document.getElementById('add-cmd-modal').classList.add('active');populateCmdSelects(); ['message-input-area','switch-input-area','local-switch-input-area','var-input-area','if-input-area','choice-input-area','teleport-input-area'].forEach(id=>document.getElementById(id).classList.remove('active')); document.getElementById('cmd-choices').style.display='none'; if(cmd.type === 'message') { showMessageInput(); document.getElementById('message-textarea').value = cmd.text; } else if(cmd.type === 'switch') { showSwitchInput(); document.getElementById('cmd-switch-select').value = cmd.switchId; } else if(cmd.type === 'local_switch') { showLocalSwitchInput(); document.getElementById('cmd-lsw-select').value = cmd.switch; } else if(cmd.type === 'variable') { showVariableInput(); document.getElementById('cmd-var-select').value = cmd.variableId; document.getElementById('cmd-var-op').value = cmd.operation; document.getElementById('cmd-var-val').value = cmd.operand; }else if(cmd.type === 'teleport') { showTeleportInput(); document.getElementById('cmd-teleport-map').value = cmd.mapId; teleportTargetX = cmd.x; teleportTargetY = cmd.y; renderTeleportPreview(); }else if(cmd.type === 'if_start') { showIfInput(); document.getElementById('cmd-if-type').value = cmd.conditionType; toggleIfUI(); if(cmd.conditionType === 'switch') { document.getElementById('cmd-if-sw-select').value = cmd.switchId; document.getElementById('cmd-if-sw-val').value = cmd.conditionValue ? 'true' : 'false'; } else if(cmd.conditionType === 'local_switch') { document.getElementById('cmd-if-lsw-select').value = cmd.switch; document.getElementById('cmd-if-lsw-val').value = cmd.conditionValue ? 'true' : 'false'; } else { document.getElementById('cmd-if-var-select').value = cmd.variableId; document.getElementById('cmd-if-var-op').value = cmd.conditionOp; document.getElementById('cmd-if-var-val').value = cmd.conditionVal; } } else if(cmd.type === 'choice') { showChoiceInput(); document.getElementById('cmd-choice-1').value = cmd.choices[0] || ''; document.getElementById('cmd-choice-2').value = cmd.choices[1] || ''; document.getElementById('cmd-choice-3').value = cmd.choices[2] || ''; document.getElementById('cmd-choice-4').value = cmd.choices[3] || ''; document.getElementById('cmd-choice-cancel').value = cmd.cancelType; }}
function closeAddCmdModal(){document.getElementById('add-cmd-modal').classList.remove('active');}
function showMessageInput(){document.getElementById('cmd-choices').style.display='none';document.getElementById('message-input-area').classList.add('active');document.getElementById('message-textarea').focus();}
function showSwitchInput(){document.getElementById('cmd-choices').style.display='none';document.getElementById('switch-input-area').classList.add('active');}
function showLocalSwitchInput(){document.getElementById('cmd-choices').style.display='none';document.getElementById('local-switch-input-area').classList.add('active');}
function showVariableInput(){document.getElementById('cmd-choices').style.display='none';document.getElementById('var-input-area').classList.add('active');}
function showIfInput(){document.getElementById('cmd-choices').style.display='none';document.getElementById('if-input-area').classList.add('active');toggleIfUI();}
function showChoiceInput(){document.getElementById('cmd-choices').style.display='none';document.getElementById('choice-input-area').classList.add('active');}
function showTeleportInput(){document.getElementById('cmd-choices').style.display='none';document.getElementById('teleport-input-area').classList.add('active'); populateTeleportSelect(); }
function toggleIfUI(){const t=document.getElementById('cmd-if-type').value;document.getElementById('if-sw-params').style.display=t==='switch'?'flex':'none';document.getElementById('if-lsw-params').style.display=t==='local_switch'?'flex':'none';document.getElementById('if-var-params').style.display=t==='variable'?'flex':'none';}
function saveMessageCommand(){const t=document.getElementById('message-textarea').value.trim();if(t!==""){const cmds=getCurrentPage().commands;if(isEditingCommand) { cmds[editCommandIndex] = {type:'message',text:t}; } else { cmds.splice(activeLineIndex,0,{type:'message',text:t}); }renderScriptLines();closeAddCmdModal();}}
function saveSwitchCommand(val){const swId=parseInt(document.getElementById('cmd-switch-select').value);const cmds=getCurrentPage().commands;if(isEditingCommand) { cmds[editCommandIndex] = {type:'switch',switchId:swId,value:val}; } else { cmds.splice(activeLineIndex,0,{type:'switch',switchId:swId,value:val}); }renderScriptLines();closeAddCmdModal();}
function saveLocalSwitchCommand(val){const swName=document.getElementById('cmd-lsw-select').value;const cmds=getCurrentPage().commands;if(isEditingCommand) { cmds[editCommandIndex] = {type:'local_switch',switch:swName,value:val}; } else { cmds.splice(activeLineIndex,0,{type:'local_switch',switch:swName,value:val}); }renderScriptLines();closeAddCmdModal();}
function saveVariableCommand(){const vId=parseInt(document.getElementById('cmd-var-select').value);const op=document.getElementById('cmd-var-op').value;const val=parseInt(document.getElementById('cmd-var-val').value)||0;const cmds=getCurrentPage().commands;if(isEditingCommand) { cmds[editCommandIndex] = {type:'variable',variableId:vId,operation:op,operand:val}; } else { cmds.splice(activeLineIndex,0,{type:'variable',variableId:vId,operation:op,operand:val}); }renderScriptLines();closeAddCmdModal();}
function saveIfCommand(){const t=document.getElementById('cmd-if-type').value; let condObj={conditionType:t};if(t==='switch'){condObj.switchId=parseInt(document.getElementById('cmd-if-sw-select').value);condObj.conditionValue=document.getElementById('cmd-if-sw-val').value==='true';} else if(t==='local_switch'){condObj.switch=document.getElementById('cmd-if-lsw-select').value;condObj.conditionValue=document.getElementById('cmd-if-lsw-val').value==='true';} else {condObj.variableId=parseInt(document.getElementById('cmd-if-var-select').value);condObj.conditionOp=document.getElementById('cmd-if-var-op').value;condObj.conditionVal=parseInt(document.getElementById('cmd-if-var-val').value)||0;}const cmds=getCurrentPage().commands;if(isEditingCommand) { cmds[editCommandIndex] = {type:'if_start', ...condObj}; } else { cmds.splice(activeLineIndex, 0, {type:'if_start',...condObj}, null, {type:'else'}, null, {type:'if_end'}); }renderScriptLines();closeAddCmdModal();}
function saveChoiceCommand(){ const c1=document.getElementById('cmd-choice-1').value.trim(); const c2=document.getElementById('cmd-choice-2').value.trim(); const c3=document.getElementById('cmd-choice-3').value.trim(); const c4=document.getElementById('cmd-choice-4').value.trim(); const cancel=document.getElementById('cmd-choice-cancel').value; if(!c1 || !c2) { alert("Нужно минимум 2 варианта!"); return; } const choices = [c1, c2]; if(c3) choices.push(c3); if(c4) choices.push(c4); const cmds=getCurrentPage().commands; if(isEditingCommand) { cmds[editCommandIndex].choices = choices; cmds[editCommandIndex].cancelType = cancel; for(let i=editCommandIndex+1; i<cmds.length; i++){ if(cmds[i] && cmds[i].type === 'choice_end') break; if(cmds[i] && cmds[i].type === 'choice_branch') { if(cmds[i].branchIndex < choices.length) cmds[i].text = choices[cmds[i].branchIndex]; } } } else { cmds.splice(activeLineIndex, 0, {type:'choice', choices: choices, cancelType: cancel}, {type:'choice_branch', branchIndex: 0, text: c1}, null, {type:'choice_branch', branchIndex: 1, text: c2}, null); let offset = 6; if(c3) { cmds.splice(activeLineIndex + offset, 0, {type:'choice_branch', branchIndex: 2, text: c3}, null); offset += 2; } if(c4) { cmds.splice(activeLineIndex + offset, 0, {type:'choice_branch', branchIndex: 3, text: c4}, null); offset += 2; } cmds.splice(activeLineIndex + offset, 0, {type:'choice_end'}); } renderScriptLines();closeAddCmdModal(); }
function populateTeleportSelect() { const sel = document.getElementById('cmd-teleport-map'); sel.innerHTML = ''; maps.forEach(m => { const opt = document.createElement('option'); opt.value = m.mapId; opt.innerText = m.name; sel.appendChild(opt); }); teleportTargetX = 0; teleportTargetY = 0; renderTeleportPreview(); }
function renderTeleportPreview() { const mapId = document.getElementById('cmd-teleport-map').value; const map = maps.find(m => m.mapId === mapId); if (!map) return; ensureLayerFormat(map); teleportCanvas.width = map.width * TILE_SIZE; teleportCanvas.height = map.height * TILE_SIZE; teleportCtx.clearRect(0, 0, teleportCanvas.width, teleportCanvas.height); drawMapOnCanvas(teleportCtx, map, false, false); drawMapOnCanvas(teleportCtx, map, false, true); if (teleportTargetX >= map.width) teleportTargetX = map.width - 1; if (teleportTargetY >= map.height) teleportTargetY = map.height - 1; if (teleportTargetX < 0) teleportTargetX = 0; if (teleportTargetY < 0) teleportTargetY = 0; teleportCtx.fillStyle = 'rgba(255, 0, 0, 0.4)'; teleportCtx.fillRect(teleportTargetX * TILE_SIZE, teleportTargetY * TILE_SIZE, TILE_SIZE, TILE_SIZE); teleportCtx.strokeStyle = 'yellow'; teleportCtx.lineWidth = 4; teleportCtx.strokeRect(teleportTargetX * TILE_SIZE, teleportTargetY * TILE_SIZE, TILE_SIZE, TILE_SIZE); document.getElementById('teleport-coords-display').innerText = `Координаты: X: ${teleportTargetX}, Y: ${teleportTargetY}`; }
teleportCanvas.addEventListener('mousedown', (e) => { handleTeleportClick(e); }); teleportCanvas.addEventListener('touchstart', (e) => { e.preventDefault(); handleTeleportClick(e.touches[0]); }, {passive: false});
function handleTeleportClick(e) { const rect = teleportCanvas.getBoundingClientRect(); const x = Math.floor((e.clientX - rect.left) * (teleportCanvas.width / rect.width) / TILE_SIZE); const y = Math.floor((e.clientY - rect.top) * (teleportCanvas.height / rect.height) / TILE_SIZE); const mapId = document.getElementById('cmd-teleport-map').value; const map = maps.find(m => m.mapId === mapId); if (map && x >= 0 && x < map.width && y >= 0 && y < map.height) { teleportTargetX = x; teleportTargetY = y; renderTeleportPreview(); } }
function saveTeleportCommand(){const mapId = document.getElementById('cmd-teleport-map').value; const cmds=getCurrentPage().commands;if(isEditingCommand) { cmds[editCommandIndex] = {type:'teleport', mapId: mapId, x: teleportTargetX, y: teleportTargetY}; } else { cmds.splice(activeLineIndex,0,{type:'teleport', mapId: mapId, x: teleportTargetX, y: teleportTargetY}); }renderScriptLines();closeAddCmdModal();}
function deleteEditingCommand() { if(!isEditingCommand) return; const cmds=getCurrentPage().commands; const cmd = cmds[editCommandIndex]; if(cmd.type === 'choice' || cmd.type === 'if_start') { const targetType = cmd.type === 'choice' ? 'choice_end' : 'if_end'; const openType = cmd.type; let depth = 1; for (let j = editCommandIndex + 1; j < cmds.length; j++) { if (cmds[j] && cmds[j].type === openType) depth++; else if (cmds[j] && cmds[j].type === targetType) { depth--; if (depth === 0) { cmds.splice(editCommandIndex, j - editCommandIndex + 1); break; } } } } else { cmds.splice(editCommandIndex, 1); } renderScriptLines();closeAddCmdModal(); }
function populateCmdSelects(){const swSel=document.getElementById('cmd-switch-select');swSel.innerHTML='';gameSwitches.forEach(s=>swSel.innerHTML+=`<option value="${s.id}">[S${s.id}] ${s.name}</option>`); const newSwOpt = document.createElement('option'); newSwOpt.value="-2"; newSwOpt.innerText="[ + Новый ]"; swSel.appendChild(newSwOpt); const vSel=document.getElementById('cmd-var-select');vSel.innerHTML='';gameVariables.forEach(v=>vSel.innerHTML+=`<option value="${v.id}">[V${v.id}] ${v.name}</option>`);const ifSwSel=document.getElementById('cmd-if-sw-select');ifSwSel.innerHTML='';gameSwitches.forEach(s=>ifSwSel.innerHTML+=`<option value="${s.id}">[S${s.id}] ${s.name}</option>`); const newIfSwOpt = document.createElement('option'); newIfSwOpt.value="-2"; newIfSwOpt.innerText="[ + Новый ]"; ifSwSel.appendChild(newIfSwOpt); const ifVarSel=document.getElementById('cmd-if-var-select');ifVarSel.innerHTML='';gameVariables.forEach(v=>ifVarSel.innerHTML+=`<option value="${v.id}">[V${v.id}] ${v.name}</option>`);}

