function openCreateMapModal(){ editingMapIndex = -1; document.getElementById('new-map-name').value="MAP"+String(maps.length+1).padStart(3,'0'); document.getElementById('new-map-width').value=17; document.getElementById('new-map-height').value=13; document.querySelector('#create-map-modal .modal-header span').innerText = "Новая карта"; document.querySelector('#create-map-modal .create-map-save-btn').innerText = "Создать"; document.getElementById('create-map-modal').classList.add('active'); }
function openMapSettingsModal(index) { editingMapIndex = index; const m = maps[index]; document.getElementById('new-map-name').value = m.name; document.getElementById('new-map-width').value = m.width; document.getElementById('new-map-height').value = m.height; document.querySelector('#create-map-modal .modal-header span').innerText = "Настройки карты"; document.querySelector('#create-map-modal .create-map-save-btn').innerText = "Сохранить"; document.getElementById('create-map-modal').classList.add('active'); }
function saveMapOrCreate(){ const n=document.getElementById('new-map-name').value||"Map"; const w=parseInt(document.getElementById('new-map-width').value)||17; const h=parseInt(document.getElementById('new-map-height').value)||13; if (editingMapIndex >= 0) { const m = maps[editingMapIndex]; m.name = n; if (m.width !== w || m.height !== h) { const nd=createEmptyMap(w,h); for(let y=0;y<Math.min(h,m.height);y++) for(let x=0;x<Math.min(w,m.width);x++) nd[y][x]=m.mapData[y][x]; m.width=w; m.height=h; m.mapData=nd; if(m.playerStartPos&&(m.playerStartPos.x>=w||m.playerStartPos.y>=h)) m.playerStartPos=null; for (let key in m.eventsData) { const [ex, ey] = key.split(',').map(Number); if (ex >= w || ey >= h) delete m.eventsData[key]; } } switchMap(editingMapIndex); } else { const mapId = 'map_' + Date.now(); maps.push({mapId: mapId, name:n, width:w, height:h, mapData:createEmptyMap(w,h), eventsData:{}, playerStartPos:null}); switchMap(maps.length-1); } closeCreateMapModal(); }
function closeCreateMapModal(){document.getElementById('create-map-modal').classList.remove('active');}

