let currentDbTab = 'player';
function openDatabase() { currentDbTab = 'player'; renderDbContent(); document.getElementById('database-modal').classList.add('active'); document.getElementById('overlay').classList.add('active'); document.querySelectorAll('.db-tab').forEach((t,i)=>t.classList.toggle('active', i===0)); }
function closeDatabase() { document.getElementById('database-modal').classList.remove('active'); document.getElementById('overlay').classList.remove('active'); renderTilesetTabs(); renderPalette(); renderEditorMap(); }
function switchDbTab(t) { currentDbTab=t; document.querySelectorAll('.db-tab').forEach(e=>e.classList.remove('active')); event.target.classList.add('active'); renderDbContent(); }
function renderDbContent() { const c = document.getElementById('db-content'); if (currentDbTab === 'player') { let charOptions = '<option value="-1">Нет</option>'; projectCharacters.forEach(ch => { charOptions += `<option value="${ch.id}" ${projectPlayer.graphicCharId === ch.id ? 'selected' : ''}>${ch.name}</option>`; }); c.innerHTML = `<div class="db-player-section"><div class="db-player-form"><div class="ev-input-group"><input type="text" id="db-player-name" value="${projectPlayer.name}" onchange="projectPlayer.name=this.value"></div><div class="ev-input-group"><label>Графика:</label><select id="db-player-graphic" onchange="updatePlayerGraphicDb()">${charOptions}</select></div><div id="db-player-graphic-preview"></div></div><div class="db-player-avatar-box"><label>Аватар:</label><img src="${projectPlayer.faceSrc || ''}" class="db-avatar-preview" style="display: ${projectPlayer.faceSrc ? 'block' : 'none'};"><button class="db-btn-sm" onclick="document.getElementById('import-face-input').click()">📂 Загрузить</button></div></div>`; updatePlayerGraphicDb(); } else if (currentDbTab === 'tilesets') { let html = ''; projectTilesets.forEach(ts => { html += `<div class="db-tileset-card"><div class="db-tileset-header"><strong>${ts.name}</strong> <span class="default-badge">Слот</span> <div><button class="db-btn-sm" onclick="document.getElementById('import-tileset-input').dataset.tsId='${ts.id}'; document.getElementById('import-tileset-input').click();">📂 Загрузить</button></div></div>`; if (ts.imageSrc && ts.image) { const imgW = ts.image.width / TILE_SIZE; const imgH = ts.image.height / TILE_SIZE; html += `<div class="db-tile-img-container"><img src="${ts.imageSrc}"><div class="db-tile-grid-overlay" style="grid-template-columns: repeat(${imgW}, 1fr); grid-template-rows: repeat(${imgH}, 1fr);">`; for (let i = 1; i <= imgW * imgH; i++) { const pass = ts.passability[i] || 0; const icon = pass === 0 ? '○' : pass === 1 ? '✖' : '★'; const iconColor = pass === 0 ? '#4CAF50' : pass === 1 ? '#f44336' : '#FFEB3B'; html += `<div class="db-tile-cell" onclick="cycleTilePass(${ts.id}, ${i})"><span id="pass-icon-${ts.id}-${i}" class="pass-icon" style="color:${iconColor}">${icon}</span></div>`; } html += `</div></div>`; } else { html += `<div style="color:#888;font-size:12px; padding: 10px;">Нет изображения (нажмите 📂 Загрузить).</div>`; } html += `</div>`; }); if (isAdminMode) { html += `<button style="margin-top:10px;padding:10px;background:#9C27B0;color:white;border:none;cursor:pointer;width:100%;font-size:14px;font-weight:bold;" onclick="savePassabilityAsDefault()">🛠️ Сохранить проходимости по умолчанию (Admin)</button>`; } c.innerHTML = html; } else if (currentDbTab === 'characters') { let html = ''; projectCharacters.forEach(ch => { html += `<div class="db-char-card"><div class="db-char-header"><strong>${ch.name}</strong> ${ch.isDefault ? '<span class="default-badge">RTP</span>' : ''} <div>${!ch.isDefault ? `<button class="db-btn-sm" onclick="document.getElementById('import-char-input').dataset.charId='${ch.id}'; document.getElementById('import-char-input').click();">📂 Загрузить</button>` : ''}</div></div>`; if(ch.image) { html += `<img src="${ch.imageSrc}" class="db-char-preview">`; } html += `</div>`; }); html += `<button style="margin-top:10px;padding:8px;background:#4CAF50;color:white;border:none;cursor:pointer;" onclick="addNewCharacter()">+ Добавить</button>`; c.innerHTML = html; } else if (currentDbTab === 'switches') { let html = ''; gameSwitches.forEach(sw => { html += `<div class="db-switch-item"><span style="width:30px;color:#aaa;">S${sw.id}:</span><input type="text" value="${sw.name}" onchange="renameSwitch(${sw.id}, this.value)"></div>`; }); html += `<button style="margin-top:15px;padding:8px;background:#4CAF50;color:white;border:none;cursor:pointer;" onclick="addNewSwitch()">+ Добавить</button>`; c.innerHTML = html; } else if (currentDbTab === 'variables') { let html = ''; gameVariables.forEach(v => { html += `<div class="db-var-item"><span style="width:30px;color:#aaa;">V${v.id}:</span><input type="text" value="${v.name}" onchange="renameVariable(${v.id}, this.value)"></div>`; }); html += `<button style="margin-top:15px;padding:8px;background:#4CAF50;color:white;border:none;cursor:pointer;" onclick="addNewVariable()">+ Добавить</button>`; c.innerHTML = html; } }
function updatePlayerGraphicDb() { const cId = parseInt(document.getElementById('db-player-graphic').value); projectPlayer.graphicCharId = cId; const box = document.getElementById('db-player-graphic-preview'); box.innerHTML = ''; if(cId !== -1) { const char = projectCharacters.find(c => c.id === cId); if(char && char.image && char.image.width > 0) { const container = document.createElement('div'); container.style.display = 'flex'; container.style.flexWrap = 'wrap'; container.style.gap = '4px'; container.style.maxWidth = '320px'; const charsPerRow = Math.floor(char.image.width / (TILE_SIZE * 3)) || 1; const charsPerCol = Math.floor(char.image.height / (TILE_SIZE * 4)) || 1; const totalChars = charsPerRow * charsPerCol; for(let i = 0; i < totalChars; i++) { const charDiv = document.createElement('div'); charDiv.style.width = '64px'; charDiv.style.height = '64px'; charDiv.style.borderRadius = '4px'; charDiv.style.cursor = 'pointer'; charDiv.style.border = i === projectPlayer.graphicCharIndex ? '3px solid #4CAF50' : '3px solid #555'; charDiv.style.backgroundColor = '#111'; charDiv.style.backgroundImage = `url(${char.imageSrc})`; charDiv.style.imageRendering = 'pixelated'; const bgW = charsPerRow * 3 * 64; const bgH = charsPerCol * 4 * 64; charDiv.style.backgroundSize = `${bgW}px ${bgH}px`; const bgX = (i % charsPerRow) * 3 * 64 + 1 * 64; const bgY = Math.floor(i / charsPerRow) * 4 * 64; charDiv.style.backgroundPosition = `-${bgX}px -${bgY}px`; charDiv.onclick = () => { projectPlayer.graphicCharIndex = i; updatePlayerGraphicDb(); }; container.appendChild(charDiv); } box.appendChild(container); } } }
function handleFaceImport(event) { const file = event.target.files[0]; if (!file) return; const reader = new FileReader(); reader.onload = function(e) { projectPlayer.faceSrc = e.target.result; const img = new Image(); img.onload = () => { projectPlayer.faceImg = img; renderDbContent(); }; img.src = projectPlayer.faceSrc; }; reader.readAsDataURL(file); event.target.value = ""; }
function cycleTilePass(tsId, tIdx) { const ts = projectTilesets.find(t => t.id === tsId); if(ts) { let val = ts.passability[tIdx] || 0; val = (val + 1) % 3; ts.passability[tIdx] = val; const span = document.getElementById(`pass-icon-${tsId}-${tIdx}`); if(span) { const icons = ['○', '✖', '★']; const colors = ['#4CAF50', '#f44336', '#FFEB3B']; span.innerText = icons[val]; span.style.color = colors[val]; } renderEditorMap(); } }
function addNewTileset() { const newId = projectTilesets.length > 0 ? Math.max(...projectTilesets.map(t=>t.id)) + 1 : 1; projectTilesets.push({id: newId, name: "Кастом " + newId, imageSrc: "", image: null, passability: {}, isDefault: false}); renderDbContent(); }
function handleTilesetImport(event) { const file = event.target.files[0]; if (!file) return; const tsId = parseInt(event.target.dataset.tsId); const reader = new FileReader(); reader.onload = function(e) { const ts = projectTilesets.find(t => t.id === tsId); if(ts) { ts.imageSrc = e.target.result; ts.passability = {}; ts.isDefault = false; const img = new Image(); img.onload = () => { ts.image = img; activeTilesetId = ts.id; renderDbContent(); renderTilesetTabs(); renderPalette(); }; img.src = ts.imageSrc; } }; reader.readAsDataURL(file); event.target.value = ""; }
function addNewCharacter() { const newId = projectCharacters.length > 0 ? Math.max(...projectCharacters.map(c=>c.id)) + 1 : 1; projectCharacters.push({id: newId, name: "Кастом Персонаж "+newId, imageSrc: "", image: null, isDefault: false}); renderDbContent(); }
function handleCharImport(event) { const file = event.target.files[0]; if (!file) return; const charId = parseInt(event.target.dataset.charId); const reader = new FileReader(); reader.onload = function(e) { const ch = projectCharacters.find(c => c.id === charId); if(ch) { ch.imageSrc = e.target.result; ch.isDefault = false; const img = new Image(); img.onload = () => { ch.image = img; renderDbContent(); renderEditorMap(); }; img.src = ch.imageSrc; } }; reader.readAsDataURL(file); event.target.value = ""; }
function renameSwitch(id, name) { const sw=gameSwitches.find(s=>s.id===id);if(sw)sw.name=name; }
function addNewSwitch() { const newId=gameSwitches.length>0?Math.max(...gameSwitches.map(s=>s.id))+1:1;gameSwitches.push({id:newId,name:"Переключатель "+newId,state:false});renderDbContent(); }
function renameVariable(id, name) { const v=gameVariables.find(x=>x.id===id);if(v)v.name=name; }
function addNewVariable() { const newId=gameVariables.length>0?Math.max(...gameVariables.map(v=>v.id))+1:1;gameVariables.push({id:newId,name:"Переменная "+newId,value:0});renderDbContent(); }
function toggleAdminMode() { isAdminMode = document.getElementById('admin-toggle').checked; if (currentDbTab === 'tilesets') renderDbContent(); }
function savePassabilityAsDefault() { const passData = {}; projectTilesets.forEach(ts => { passData[ts.id] = ts.passability; }); localStorage.setItem('rpgmaker_default_passability', JSON.stringify(passData)); const jsonStr = JSON.stringify(passData); prompt("✅ Проходимость по умолчанию сохранена!\nДля встраивания в код скопируй JSON ниже и вставь в DEFAULT_RTP.tilesets[i].passability:", jsonStr); }

// ====================================================================
// ==================== СОХРАНЕНИЕ/ЗАГРУЗКА ====================
// ====================================================================

function saveProject() { const saveData = JSON.parse(JSON.stringify({ maps, projectTilesets, projectCharacters, projectPlayer, gameSwitches, gameVariables })); saveData.projectTilesets.forEach(ts => { if(ts.isDefault) delete ts.imageSrc; }); saveData.projectCharacters.forEach(ch => { if(ch.isDefault) delete ch.imageSrc; }); if(projectPlayer.faceImg) delete projectPlayer.faceImg; const json = JSON.stringify(saveData, null, 2); const blob = new Blob([json], {type: "application/json"}); const url = URL.createObjectURL(blob); const a = document.createElement("a"); a.href = url; a.download = "project.rpgm"; a.click(); URL.revokeObjectURL(url); }
function loadProject(event) { const file = event.target.files[0]; if (!file) return; const reader = new FileReader(); reader.onload = function(e) { try { const data = JSON.parse(e.target.result); if(data.maps) maps = data.maps; if(data.gameSwitches) gameSwitches = data.gameSwitches; if(data.gameVariables) gameVariables = data.gameVariables; if(data.projectPlayer) { projectPlayer = data.projectPlayer; if(projectPlayer.faceSrc) { const img = new Image(); img.onload = () => { projectPlayer.faceImg = img; }; img.src = projectPlayer.faceSrc; } } if(data.projectTilesets) { projectTilesets = data.projectTilesets; projectTilesets.forEach(ts => { const defTs = DEFAULT_RTP.tilesets.find(d => d.id === ts.id); if(ts.isDefault && defTs && !ts.imageSrc) ts.imageSrc = defTs.path; if(ts.imageSrc) { const img = new Image(); img.onload = () => { ts.image = img; renderEditorMap(); renderTilesetTabs(); renderPalette(); }; img.src = ts.imageSrc; } }); } if(data.projectCharacters) { projectCharacters = data.projectCharacters; projectCharacters.forEach(ch => { const defCh = DEFAULT_RTP.characters.find(d => d.id === ch.id); if(ch.isDefault && defCh && !ch.imageSrc) ch.imageSrc = defCh.path; if(ch.imageSrc) { const img = new Image(); img.onload = () => { ch.image = img; renderEditorMap(); }; img.src = ch.imageSrc; } }); } currentMapIndex = 0; switchMap(0); renderTilesetTabs(); renderPalette(); alert("Проект загружен!"); } catch(ex) { alert("Ошибка загрузки: " + ex); } }; reader.readAsText(file); event.target.value = ""; }
function closeTopModal() { if(document.getElementById('database-modal').classList.contains('active'))closeDatabase();else if(document.getElementById('create-map-modal').classList.contains('active'))closeCreateMapModal();else if(document.getElementById('add-cmd-modal').classList.contains('active'))closeAddCmdModal();else closeEventModal(); }

window.addEventListener('resize', () => { if(!isPlaying) renderPalette(); });
